//! Pure mesh primitives ported from x-ranger's TypeScript mesh-policy module
//! (open-source/gnosis/src/mesh-policy.ts). These are the detection and
//! containment witnesses the rogue reasons over. They mirror the Lean primitives
//! under `ForkRaceFoldTheorems.*` (AntiDomainOverlay, DiscreteSamplingDuel,
//! ZenonicBarrier, IceAntiIceCatalog, HoneyPit) that the TS version also mirrors.
//!
//! Posture note: x-ranger is a tank that advertises these traps. monster-badchild
//! reuses the same witnesses to *recognize* an observer, then misroutes quietly.
//! The functions here are pure and deterministic; the routing they inform lives in
//! `crate::detect` and `crate::policy`.

/// An additive-disjoint support region (an "overlay" footprint).
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Overlay {
    pub size: u64,
}

/// A discrete sampling clock with a fixed tick rate.
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct Clock {
    pub rate: f64,
}

/// A Zenonic gap as a rational `num / denom`. Slowloris contracts `denom` while
/// holding `num` fixed; the gap only "lands" when `num` reaches zero.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Gap {
    pub num: u64,
    pub denom: u64,
}

impl Gap {
    /// Mirrors `createGap`: numerator non-negative, denominator strictly positive.
    pub fn new(num: u64, denom: u64) -> Result<Gap, String> {
        if denom == 0 {
            return Err("Gap denominator must be positive".to_string());
        }
        Ok(Gap { num, denom })
    }
}

/// Halves the effective gap by doubling the denominator (`contractStep`).
/// Saturates instead of overflowing; the landing predicate is unaffected because
/// it depends only on the numerator.
pub fn contract_step(g: Gap) -> Gap {
    Gap {
        num: g.num,
        denom: g.denom.saturating_mul(2),
    }
}

/// Applies `contract_step` `n` times (`iterate`).
pub fn iterate(n: u64, g: Gap) -> Gap {
    let mut current = g;
    for _ in 0..n {
        current = contract_step(current);
    }
    current
}

/// True only when the numerator reaches zero (`hasLanded`). For a positive
/// initial numerator this is never true at any finite depth — the Zenonic
/// barrier (`zenonicApproachNumeratorFixed`).
pub fn has_landed(g: Gap) -> bool {
    g.num == 0
}

// ---------------------------------------------------------------------------
// Observation / intrusion witnesses (the three signatures).
// ---------------------------------------------------------------------------

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct OverlayHoleBypass {
    pub ice_size: u64,
    pub attacker_size: u64,
    pub region_size: u64,
    pub reclaimed_hits: u64,
}

/// Path-enumeration witness. The attacker reclaims hits on additive-disjoint
/// support when the defended overlay and the attacker overlay both fit inside the
/// region (`overlayHoleBypass`). Non-zero `reclaimed_hits` is the signature.
pub fn overlay_hole_bypass(ice: Overlay, attacker: Overlay, region_size: u64) -> OverlayHoleBypass {
    let disjoint_fits = ice.size.saturating_add(attacker.size) <= region_size;
    OverlayHoleBypass {
        ice_size: ice.size,
        attacker_size: attacker.size,
        region_size,
        reclaimed_hits: if disjoint_fits { attacker.size } else { 0 },
    }
}

#[derive(Debug, Clone, Copy, PartialEq)]
pub struct ClockSideChannelBypass {
    pub defender_rate: f64,
    pub attacker_rate: f64,
    pub horizon: f64,
    pub frame_deficit: f64,
    pub strictly_positive: bool,
}

/// `H * max(0, fA - fB)` — frames the attacker steals between heartbeats.
pub fn frame_deficit(horizon: f64, attacker_rate: f64, defender_rate: f64) -> f64 {
    horizon.max(0.0) * (attacker_rate - defender_rate).max(0.0)
}

/// Clock-rate side-channel witness: an attacker sampling faster than the
/// defender's heartbeat opens a strictly-positive frame deficit
/// (`clockRateSideChannel`). `strictly_positive` is the signature.
pub fn clock_side_channel_bypass(
    defender: Clock,
    attacker: Clock,
    horizon: f64,
) -> ClockSideChannelBypass {
    let h = horizon.max(0.0);
    let deficit = frame_deficit(h, attacker.rate, defender.rate);
    ClockSideChannelBypass {
        defender_rate: defender.rate,
        attacker_rate: attacker.rate,
        horizon: h,
        frame_deficit: deficit,
        strictly_positive: h > 0.0 && attacker.rate > defender.rate && deficit > 0.0,
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct ZenonicApproachBypass {
    pub initial_gap: Gap,
    pub iterations: u64,
    pub final_gap: Gap,
    pub has_landed: bool,
}

/// Slowloris witness (Zeno's dichotomy): contracting gaps that never land for a
/// positive initial numerator (`zenonicApproachBypass`). The signature is a
/// long contraction run that has *not* landed.
pub fn zenonic_approach_bypass(initial_gap: Gap, iterations: u64) -> ZenonicApproachBypass {
    let final_gap = iterate(iterations, initial_gap);
    ZenonicApproachBypass {
        initial_gap,
        iterations,
        final_gap,
        has_landed: has_landed(final_gap),
    }
}

// ---------------------------------------------------------------------------
// Honey-pit containment (the Aikido trap).
// ---------------------------------------------------------------------------

/// A bounded containment pool. `drain_slots` is a fixed server-side worker count;
/// the Aikido property is that drain work is independent of how many are trapped.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct HoneyPit {
    pub capacity: u64,
    pub inhabitants: u64,
    pub drain_slots: u64,
}

/// Mirrors `createHoneyPit` with its Lean preconditions.
pub fn create_honey_pit(capacity: u64, drain_slots: u64, inhabitants: u64) -> Result<HoneyPit, String> {
    if capacity == 0 {
        return Err("honey-pit capacity must be positive".to_string());
    }
    if drain_slots == 0 {
        return Err("honey-pit drain_slots must be positive".to_string());
    }
    if inhabitants > capacity {
        return Err("honey-pit inhabitants must not exceed capacity".to_string());
    }
    Ok(HoneyPit {
        capacity,
        inhabitants,
        drain_slots,
    })
}

/// Graceful-overflow contract: a new connection can be trapped only below capacity.
pub fn can_trap(pit: HoneyPit) -> bool {
    pit.inhabitants < pit.capacity
}

/// Admit one connection into containment (`trap`). Errors at capacity.
pub fn trap(pit: HoneyPit) -> Result<HoneyPit, String> {
    if !can_trap(pit) {
        return Err("honey-pit is at capacity".to_string());
    }
    Ok(HoneyPit {
        capacity: pit.capacity,
        inhabitants: pit.inhabitants + 1,
        drain_slots: pit.drain_slots,
    })
}

/// Server-side drain work over `ticks` (`serverDrainWork`). Linear in ticks and
/// independent of inhabitants — the `aikidoServerBound`.
pub fn server_drain_work(pit: HoneyPit, ticks: u64) -> u64 {
    pit.drain_slots.saturating_mul(ticks)
}

/// Lower bound on cumulative attacker wait (`attackerWait`): monotone in `k`,
/// with effective throughput approaching zero (`trappedAttackerThroughputZero`).
pub fn attacker_wait(k: u64, iterate_depth: u64) -> u64 {
    k.saturating_mul(iterate_depth)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn gap_rejects_zero_denominator() {
        assert!(Gap::new(1, 0).is_err());
        assert!(Gap::new(0, 1).is_ok());
    }

    #[test]
    fn zenonic_never_lands_with_positive_numerator() {
        let g = Gap::new(1, 1).unwrap();
        let r = zenonic_approach_bypass(g, 64);
        assert!(!r.has_landed, "positive numerator must never land");
        assert_eq!(r.final_gap.num, 1, "contraction holds the numerator fixed");
    }

    #[test]
    fn zenonic_already_landed_when_numerator_zero() {
        let g = Gap::new(0, 1).unwrap();
        assert!(zenonic_approach_bypass(g, 10).has_landed);
    }

    #[test]
    fn overlay_hole_bypass_reclaims_only_when_disjoint() {
        // ice 3 + attacker 4 = 7 <= region 10 -> reclaims 4.
        assert_eq!(
            overlay_hole_bypass(Overlay { size: 3 }, Overlay { size: 4 }, 10).reclaimed_hits,
            4
        );
        // ice 8 + attacker 4 = 12 > region 10 -> reclaims 0.
        assert_eq!(
            overlay_hole_bypass(Overlay { size: 8 }, Overlay { size: 4 }, 10).reclaimed_hits,
            0
        );
    }

    #[test]
    fn clock_side_channel_fires_only_when_attacker_faster() {
        let fast = clock_side_channel_bypass(Clock { rate: 1.0 }, Clock { rate: 4.0 }, 10.0);
        assert!(fast.strictly_positive);
        assert!(fast.frame_deficit > 0.0);

        let slow = clock_side_channel_bypass(Clock { rate: 4.0 }, Clock { rate: 1.0 }, 10.0);
        assert!(!slow.strictly_positive);
    }

    #[test]
    fn honeypit_preconditions_and_drain_independence() {
        assert!(create_honey_pit(0, 1, 0).is_err());
        assert!(create_honey_pit(1, 0, 0).is_err());
        assert!(create_honey_pit(2, 1, 3).is_err());

        let empty = create_honey_pit(10, 2, 0).unwrap();
        let full = create_honey_pit(10, 2, 9).unwrap();
        // Aikido: drain work depends on drain_slots and ticks, not inhabitants.
        assert_eq!(server_drain_work(empty, 5), server_drain_work(full, 5));
    }

    #[test]
    fn trap_respects_capacity() {
        let pit = create_honey_pit(1, 1, 0).unwrap();
        let pit = trap(pit).unwrap();
        assert!(!can_trap(pit));
        assert!(trap(pit).is_err());
    }
}
